1503	        top_k = 5
1504	    } = {}) {
1505	
1506	        const sampling_rate = this.processor.feature_extractor.config.sampling_rate;
1507	        const preparedAudios = await prepareAudios(audio, sampling_rate);
1508	
1509	        // @ts-expect-error TS2339
1510	        const id2label = this.model.config.id2label;
1511	
1512	        const toReturn = [];
1513	        for (const aud of preparedAudios) {
1514	            const inputs = await this.processor(aud);
1515	            const output = await this.model(inputs);
1516	            const logits = output.logits[0];
1517	
1518	            const scores = await topk(new Tensor(
1519	                'float32',
1520	                softmax(logits.data),
1521	                logits.dims,
1522	            ), top_k);
1523	
1524	            const values = scores[0].tolist();
1525	            const indices = scores[1].tolist();
1526	
1527	            const vals = indices.map((x, i) => ({
1528	                label: /** @type {string} */ (id2label ? id2label[x] : `LABEL_${x}`),
1529	                score: /** @type {number} */ (values[i]),
1530	            }));
1531	
1532	            toReturn.push(vals);
1533	        };
