#### B. DocumentQuestionAnsweringPipeline
**File:** `pipelines.js` (lines 2732-2779)
**Task Name:** `"document-question-answering"`
**Purpose:** Answer questions about document images (like invoices, forms)
**Model Class:** `AutoModelForDocumentQuestionAnswering`

**Implementation:**
```javascript
export class DocumentQuestionAnsweringPipeline extends Pipeline {
    constructor(options) {
        super(options);
    }

    async _call(image, question, generate_kwargs = {}) {
        // Preprocess image
        const preparedImage = (await prepareImages(image))[0];
        const { pixel_values } = await this.processor(preparedImage);

        // Run tokenization
        const task_prompt = `<s_docvqa><s_question>${question}</s_question><s_answer>`;
        const decoder_input_ids = this.tokenizer(task_prompt, {
            add_special_tokens: false,
            padding: true,
            truncation: true,
        }).input_ids;

        // Run model
        const output = await this.model.generate({
            inputs: pixel_values,
            max_length: this.model.config.decoder.max_position_embeddings,
            decoder_input_ids,
            ...generate_kwargs,
        });

        // Decode output
        const decoded = this.tokenizer.batch_decode(output)[0];

        // Parse answer
        const match = decoded.match(/<s_answer>(.*?)<\/s_answer>/);
        let answer = null;
        if (match && match.length >= 2) {
            answer = match[1].trim();
        }
        return [{ answer }];
    }
}
```

**Typedef Definition (lines 2705-2716):**
```javascript
/**
 * @typedef {Object} DocumentQuestionAnsweringSingle
 * @property {string} answer The generated text.
 * @typedef {DocumentQuestionAnsweringSingle[]} DocumentQuestionAnsweringOutput
 *
 * @callback DocumentQuestionAnsweringPipelineCallback
 * @param {ImageInput} image The image of the document.
 * @param {string} question A question to ask of the document.
 * @param {Partial<GenerationConfig>} [options] Additional generation kwargs.
 * @returns {Promise<DocumentQuestionAnsweringOutput|DocumentQuestionAnsweringOutput[]>}
 *
 * @typedef {TextImagePipelineConstructorArgs & DocumentQuestionAnsweringPipelineCallback & Disposable} DocumentQuestionAnsweringPipelineType
 */
```

