12	function _prompt_split_image(image_seq_len, image_rows, image_cols, fake_token_around_image, image_token, global_img_token) {
13	    let text_split_images = "";
14	    for (let n_h = 0; n_h < image_rows; ++n_h) {
15	        for (let n_w = 0; n_w < image_cols; ++n_w) {
16	            text_split_images += (
17	                fake_token_around_image +
18	                `<row_${n_h + 1}_col_${n_w + 1}>` +
19	                image_token.repeat(image_seq_len)
20	            );
21	        }
22	        text_split_images += "\n";
23	    }
24	
